fast_full_mismatch_patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..e1aa23c698a5 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,6 +8790,84 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // fcmp (fptrunc X), C -> fcmp X, C' after adjusting for rounding.
+  // We only handle ordered inequality predicates for normal numbers.
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C))) {
+      const fltSemantics &SrcFPSem =
+          X->getType()->getScalarType()->getFltSemantics();
+      bool LossyExt;
+      // Extend the float constant to the source type (always exact).
+      APFloat ExtC = *C;
+      ExtC.convert(SrcFPSem, APFloat::rmNearestTiesToEven, &LossyExt);
+
+      // Only handle finite, normal numbers for now.
+      // Skip ppc_fp128 (double-double) source types; DoubleAPFloat::next()
+      // may crash for certain values.
+      if (!LossyExt && C->isNormal() &&
+          &SrcFPSem != &APFloat::PPCDoubleDouble() &&
+          (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
+           Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT ||
+           Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE ||
+           Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT)) {
+        APFloat NextC = *C;
+        NextC.next(false); // nextUp
+        APFloat PrevC = *C;
+        PrevC.next(true); // nextDown
+
+        // Extend to source type.
+        APFloat NextD = NextC;
+        NextD.convert(SrcFPSem, APFloat::rmNearestTiesToEven, &LossyExt);
+        APFloat PrevD = PrevC;
+        PrevD.convert(SrcFPSem, APFloat::rmNearestTiesToEven, &LossyExt);
+
+        // Compute half-way points.
+        APFloat Two(SrcFPSem, 2);
+        APFloat HalfAbove = (ExtC + NextD) / Two;
+        APFloat HalfBelow = (ExtC + PrevD) / Two;
+
+        // Check if C has an even mantissa LSB (for ties-to-even rounding).
+        bool IsEven = C->bitcastToAPInt()[0] == 0; // bit 0 is LSB (even parity)
+        bool NextIsEven = NextC.bitcastToAPInt()[0] == 0;
+
+        APFloat Threshold(SrcFPSem);
+        switch (Pred) {
+        case FCmpInst::FCMP_OGE:
+        case FCmpInst::FCMP_UGE:
+          Threshold = HalfBelow;
+          if (!IsEven)
+            Threshold.next(false);
+          break;
+        case FCmpInst::FCMP_OGT:
+        case FCmpInst::FCMP_UGT:
+          Threshold = HalfAbove;
+          if (!NextIsEven)
+            Threshold.next(false);
+          break;
+        case FCmpInst::FCMP_OLE:
+        case FCmpInst::FCMP_ULE:
+          Threshold = HalfAbove;
+          if (IsEven)
+            ; // Threshold = HalfAbove (at HalfAbove, round = C, satisfying <= C)
+          else
+            Threshold.next(true); // At HalfAbove, round = C+ULP > C, so use nextDown
+          break;
+        case FCmpInst::FCMP_OLT:
+        case FCmpInst::FCMP_ULT:
+          Threshold = HalfBelow;
+          if (IsEven)
+            Threshold.next(true); // At HalfBelow, round = C, not < C, so use nextDown
+          else
+            ; // Threshold = HalfBelow (at HalfBelow, round = C-ULP < C)
+          break;
+        }
+        Constant *NewC = ConstantFP::get(X->getType(), Threshold);
+        return new FCmpInst(Pred, X, NewC, "", &I);
+      }
+    }
+  }
+
   // Convert a sign-bit test of an FP value into a cast and integer compare.
   // TODO: Simplify if the copysign constant is 0.0 or NaN.
   // TODO: Handle non-zero compare constants.
